import{_ as t,o as a,c as d,a2 as o}from"./chunks/framework.DeNJmwJc.js";const b=JSON.parse('{"title":"Chapter 29 — Text Objects: Advanced","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/29-text-objects-advanced.md","filePath":"chapters/29-text-objects-advanced.md"}'),s={name:"chapters/29-text-objects-advanced.md"};function c(n,e,r,i,l,p){return a(),d("div",null,[...e[0]||(e[0]=[o(`<h1 id="chapter-29-—-text-objects-advanced" tabindex="-1">Chapter 29 — Text Objects: Advanced <a class="header-anchor" href="#chapter-29-—-text-objects-advanced" aria-label="Permalink to &quot;Chapter 29 — Text Objects: Advanced&quot;">​</a></h1><blockquote><p><em>&quot;Sentences, paragraphs, and blocks — Vim understands text structure.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐⭐ Intermediate <strong>Estimated Reading Time:</strong> 15 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Beyond words and brackets, Vim understands larger structural units.</p><hr><h1 id="sentence-text-objects" tabindex="-1">Sentence Text Objects <a class="header-anchor" href="#sentence-text-objects" aria-label="Permalink to &quot;Sentence Text Objects&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>is</code></td><td><strong>Inner</strong> sentence</td></tr><tr><td><code>as</code></td><td><strong>A</strong> sentence (includes spaces)</td></tr></tbody></table><p>A sentence ends with <code>.</code>, <code>!</code>, or <code>?</code>.</p><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello world. This is a test. Vim is great.</span></span>
<span class="line"><span>             ^</span></span>
<span class="line"><span></span></span>
<span class="line"><span>dis → </span></span>
<span class="line"><span></span></span>
<span class="line"><span>Hello world. Vim is great.</span></span></code></pre></div><hr><h1 id="paragraph-text-objects" tabindex="-1">Paragraph Text Objects <a class="header-anchor" href="#paragraph-text-objects" aria-label="Permalink to &quot;Paragraph Text Objects&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>ip</code></td><td><strong>Inner</strong> paragraph</td></tr><tr><td><code>ap</code></td><td><strong>A</strong> paragraph (includes blank line)</td></tr></tbody></table><p>A paragraph is separated by blank lines.</p><h2 id="example-1" tabindex="-1">Example <a class="header-anchor" href="#example-1" aria-label="Permalink to &quot;Example&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Line 1</span></span>
<span class="line"><span>Line 2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Line 3</span></span>
<span class="line"><span>Line 4</span></span></code></pre></div><p>Cursor on Line 1, press <code>dip</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>Line 3</span></span>
<span class="line"><span>Line 4</span></span></code></pre></div><hr><h1 id="block-text-objects" tabindex="-1">Block Text Objects <a class="header-anchor" href="#block-text-objects" aria-label="Permalink to &quot;Block Text Objects&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>iB</code></td><td>Inner block <code>{ }</code></td></tr><tr><td><code>aB</code></td><td>A block including braces</td></tr></tbody></table><p>These are like <code>i{</code> / <code>a{</code> but operate on the outermost block.</p><hr><h1 id="all-text-objects-quick-reference" tabindex="-1">All Text Objects Quick Reference <a class="header-anchor" href="#all-text-objects-quick-reference" aria-label="Permalink to &quot;All Text Objects Quick Reference&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Operates On</th></tr></thead><tbody><tr><td><code>iw</code> / <code>aw</code></td><td>Word</td></tr><tr><td><code>iW</code> / <code>aW</code></td><td>WORD</td></tr><tr><td><code>is</code> / <code>as</code></td><td>Sentence</td></tr><tr><td><code>ip</code> / <code>ap</code></td><td>Paragraph</td></tr><tr><td><code>i(</code> / <code>a(</code></td><td>Parentheses</td></tr><tr><td><code>i[</code> / <code>a[</code></td><td>Square brackets</td></tr><tr><td><code>i{</code> / <code>a{</code></td><td>Curly braces</td></tr><tr><td><code>i&lt;</code> / <code>a&lt;</code></td><td>Angle brackets</td></tr><tr><td><code>i&quot;</code> / <code>a&quot;</code></td><td>Double quotes</td></tr><tr><td><code>i&#39;</code> / <code>a&#39;</code></td><td>Single quotes</td></tr><tr><td>\`i\`\`</td><td>a\`\`</td></tr><tr><td><code>it</code> / <code>at</code></td><td>HTML/XML tags</td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li>Text objects let you operate on structural units.</li><li><code>is</code>/<code>as</code> for sentences, <code>ip</code>/<code>ap</code> for paragraphs.</li><li><code>iB</code>/<code>aB</code> for the outermost block.</li><li>All text objects work with <code>d</code>, <code>c</code>, <code>y</code>, <code>v</code>, <code>gu</code>, <code>gU</code>, etc.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open a text file with paragraphs and delete one with <code>dip</code>.</li><li>Use <code>dis</code> to delete a sentence.</li><li>Practice text objects until they become muscle memory.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./30-advanced-text-objects.html"><strong>Chapter 30 — Advanced Editing: Search and Replace</strong></a></p><p>Master complex search and replace operations.</p>`,38)])])}const u=t(s,[["render",c]]);export{b as __pageData,u as default};
